.bcn-search-trigger {
  display: flex;
  align-items: center;
  gap: var(--spacing-200);
  width: 100%;
  max-width: 520px;
  margin: 0 auto;
  padding: var(--spacing-150) var(--spacing-300);
  background: var(--color-surface);
  border: 1px solid var(--color-border);
  border-radius: var(--radius-200);
  cursor: text;
  transition:
    border-color 0.15s ease,
    background 0.15s ease;
}
.bcn-search-trigger .esa-icon {
  flex: none;
  color: var(--color-text-tertiary);
}
.bcn-search-trigger__placeholder {
  flex: 1;
  min-width: 0;
  text-align: left;
  overflow: hidden;
  text-overflow: ellipsis;
  white-space: nowrap;
  font-size: var(--type-size-200);
  color: var(--color-text-tertiary);
}
.bcn-search-trigger__kbd {
  display: inline-flex;
  gap: 2px;
  flex: none;
}
.bcn-search-trigger__kbd kbd {
  display: inline-flex;
  align-items: center;
  justify-content: center;
  min-width: 18px;
  height: 18px;
  padding: 0 4px;
  font-family: inherit;
  font-size: 11px;
  font-weight: var(--font-weight-medium);
  color: var(--color-text-tertiary);
  background: var(--color-surface-sunken);
  border: 1px solid var(--color-border);
  border-radius: 4px;
}
.topbar__right .esa-icon-button {
  color: var(--color-text-secondary);
}
.project-switcher__trigger > .esa-icon:first-child {
  flex-shrink: 0;
  color: var(--bcn-gray-500);
}
.nav-section__header > .esa-icon:first-child {
  flex-shrink: 0;
  color: var(--bcn-gray-950);
  transition: color 0.15s ease;
}
.nav-section__header > .esa-icon:last-child {
  color: var(--bcn-gray-400);
  transition:
    transform 0.15s ease,
    opacity 0.2s ease-in-out;
  flex-shrink: 0;
}
.breadcrumbs__items .esa-icon {
  color: var(--bcn-gray-400);
}
.page-layout__title h1 .esa-icon {
  color: var(--bcn-gray-1000);
  flex-shrink: 0;
}
.esa-icon-button {
  --_ib-size: var(--form-height-md, 40px);
  display: inline-flex;
  align-items: center;
  justify-content: center;
  width: var(--_ib-size);
  height: var(--_ib-size);
  padding: 0;
  border: 0;
  border-radius: var(--radius-200, 8px);
  background: transparent;
  color: inherit;
  cursor: pointer;
  transition: background var(--transition-fast, 0.15s ease);
  -webkit-appearance: none;
  appearance: none;
}
.esa-icon {
  --_icon-size: var(--icon-size-md, var(--icon-size-medium, 20px));
  display: inline-flex;
  align-items: center;
  justify-content: center;
  width: var(--_icon-size);
  height: var(--_icon-size);
  line-height: 1;
  color: inherit;
}
.esa-icon--xs {
  --_icon-size: var(--icon-size-xs, 14px);
}
.esa-icon svg {
  display: block;
  width: var(--_icon-size);
  height: var(--_icon-size);
}
.esa-icon--sm {
  --_icon-size: var(--icon-size-sm, var(--icon-size-small, 16px));
}
.esa-icon--md {
  --_icon-size: var(--icon-size-md, var(--icon-size-medium, 20px));
}

.bcn-omni__panel {
  position: relative;
  z-index: 1;
  width: 860px;
  max-width: 100%;
  height: min(680px, 84vh);
  display: flex;
  flex-direction: column;
  background: var(--color-surface);
  border: 1px solid var(--color-border);
  border-radius: var(--radius-400, 12px);
  overflow: hidden;
  box-shadow: 0 24px 64px #141e2852;
  animation: bcn-omni-enter 0.14s ease-out;
}
.bcn-omni__searchrow {
  display: flex;
  align-items: center;
  gap: var(--spacing-300);
  flex: none;
  padding: var(--spacing-300) var(--spacing-500);
  border-bottom: 1px solid var(--color-border);
}
.bcn-omni__searchicon {
  display: inline-flex;
  flex: none;
  color: var(--color-text-tertiary);
}
.bcn-omni__searchicon svg {
  width: 22px;
  height: 22px;
}
.bcn-omni__inputwrap {
  position: relative;
  flex: 1;
  min-width: 0;
  display: flex;
  align-items: center;
}
.bcn-omni__ghost {
  position: absolute;
  inset: 0;
  z-index: 0;
  display: flex;
  align-items: center;
  font-family: inherit;
  font-size: var(--type-size-400, 1.25rem);
  line-height: 1.4;
  color: var(--color-text-tertiary);
  white-space: pre;
  overflow: hidden;
  pointer-events: none;
}
.bcn-omni__input {
  position: relative;
  z-index: 1;
  width: 100%;
  min-width: 0;
  margin: 0;
  padding: 0;
  border: 0;
  outline: 0;
  background: transparent;
  font-family: inherit;
  font-size: var(--type-size-400, 1.25rem);
  line-height: 1.4;
  color: var(--color-text-primary);
}
.bcn-omni__input::placeholder {
  color: var(--color-text-tertiary);
}
.bcn-omni__clear {
  display: inline-flex;
  align-items: center;
  justify-content: center;
  width: 26px;
  height: 26px;
  flex: none;
  border: 0;
  border-radius: var(--radius-full);
  background: var(--color-surface-sunken);
  color: var(--color-text-secondary);
  cursor: pointer;
}
.bcn-omni__clear[hidden] {
  display: none;
}
.bcn-omni__split {
  display: flex;
  flex: 1 1 auto;
  min-height: 0;
}
.bcn-omni__rail {
  box-sizing: border-box;
  flex: none;
  width: 208px;
  display: flex;
  flex-direction: column;
  gap: 1px;
  padding: var(--spacing-200);
  border-right: 1px solid var(--color-border);
  overflow-y: auto;
  scrollbar-width: none;
}
.bcn-omni-rail__item {
  display: flex;
  align-items: center;
  gap: var(--spacing-200);
  width: 100%;
  padding: var(--spacing-150) var(--spacing-250);
  border: 0;
  border-radius: var(--radius-200);
  background: transparent;
  color: var(--color-text-secondary);
  font-family: inherit;
  font-size: var(--type-size-150);
  text-align: left;
  cursor: pointer;
  transition:
    background 0.1s,
    color 0.1s;
}
.bcn-omni-rail__item:disabled {
  color: var(--color-text-tertiary);
  cursor: default;
}
.bcn-omni-rail__label {
  flex: 1;
  min-width: 0;
  overflow: hidden;
  text-overflow: ellipsis;
  white-space: nowrap;
}
.bcn-omni__body {
  flex: 1 1 auto;
  min-width: 0;
  overflow-y: auto;
  padding: var(--spacing-200) 0;
}
.bcn-omni__body.is-landing {
  display: flex;
  align-items: center;
  justify-content: center;
  padding: var(--spacing-400);
}
.bcn-omni__showall {
  display: flex;
  align-items: center;
  justify-content: center;
  gap: var(--spacing-200);
  flex: none;
  width: 100%;
  padding: var(--spacing-300);
  border: 0;
  background: var(--color-primary);
  color: var(--color-text-inverse);
  font-family: inherit;
  font-size: var(--type-size-200);
  font-weight: var(--font-weight-semibold);
  cursor: pointer;
}
.bcn-omni__showall[hidden] {
  display: none;
}
.bcn-omni__footer {
  display: flex;
  flex-wrap: wrap;
  gap: var(--spacing-400);
  flex: none;
  padding: var(--spacing-250) var(--spacing-500);
  border-top: 1px solid var(--color-border);
  font-size: var(--type-size-150);
  color: var(--color-text-tertiary);
}
.bcn-omni__footer span {
  display: inline-flex;
  align-items: center;
  gap: 6px;
}
.bcn-omni-rail__item.is-active {
  background: var(--color-primary);
  color: var(--color-text-inverse);
  font-weight: var(--font-weight-semibold);
}
.bcn-omni-rail__c {
  flex: none;
  font-size: 11px;
  font-variant-numeric: tabular-nums;
  opacity: 0.8;
}
.bcn-omni-group__head {
  display: flex;
  align-items: center;
  gap: var(--spacing-200);
  padding: var(--spacing-200) var(--spacing-400) var(--spacing-100);
}
.bcn-omni-group__label {
  font-size: var(--type-size-150);
  font-weight: var(--font-weight-semibold);
  color: var(--color-text-primary);
}
.bcn-omni-group__count {
  font-size: var(--type-size-100);
  font-variant-numeric: tabular-nums;
  color: var(--color-text-secondary);
  background: transparent;
  border: 1px solid var(--color-border);
  border-radius: var(--radius-100);
  padding: 0 6px;
  line-height: 1.5;
}
.bcn-omni-row {
  display: flex;
  align-items: center;
  width: 100%;
  padding: var(--spacing-150) var(--spacing-400);
  border: 0;
  background: transparent;
  color: var(--color-text-primary);
  font-family: inherit;
  text-align: left;
  cursor: pointer;
}
.bcn-omni-row.is-active {
  background: var(--color-surface-sunken);
}
.bcn-omni-row__text {
  flex: 1;
  min-width: 0;
  display: flex;
  flex-direction: column;
  gap: 1px;
}
.bcn-omni-row__titlerow {
  display: flex;
  align-items: center;
  gap: var(--spacing-150);
  min-width: 0;
}
.bcn-omni-row__code {
  flex: none;
  padding: 1px 6px;
  border-radius: var(--radius-100);
  font-size: var(--type-size-100);
  font-weight: var(--font-weight-semibold);
  line-height: 1.4;
  white-space: nowrap;
  color: var(--color-commitment);
  background: color-mix(in srgb, var(--color-commitment) 12%, white);
}
.bcn-omni-row__title {
  flex: 0 1 auto;
  min-width: 0;
  font-size: var(--type-size-150);
  font-weight: var(--font-weight-medium);
  color: var(--color-text-primary);
  white-space: nowrap;
  overflow: hidden;
  text-overflow: ellipsis;
}
.bcn-omni-row__snippet {
  margin-top: 2px;
  font-family: var(--font-decorative);
  font-size: var(--type-size-150);
  color: var(--color-text-primary);
  white-space: nowrap;
  overflow: hidden;
  text-overflow: ellipsis;
}
.bcn-omni-row mark,
.bcn-omni-empty mark {
  background: #fde047;
  color: var(--color-text-primary);
  border-radius: 2px;
  padding: 0 1px;
}

.bcn-sr {
  display: flex;
  flex-direction: column;
  gap: var(--spacing-400);
}
.bcn-sr__search {
  display: flex;
  align-items: center;
  gap: var(--spacing-300);
  padding: var(--spacing-300) var(--spacing-400);
  background: var(--color-surface);
  border: 1px solid var(--color-border);
  border-radius: var(--radius-300);
}
.bcn-sr__search-icon {
  display: inline-flex;
  flex-shrink: 0;
  color: var(--color-text-tertiary);
}
.bcn-sr__search-icon svg {
  width: 20px;
  height: 20px;
}
.bcn-sr__input {
  flex: 1;
  min-width: 0;
  border: none;
  outline: none;
  background: transparent;
  font-family: inherit;
  font-size: var(--type-size-300);
  color: var(--color-text-primary);
}
.bcn-sr__input::placeholder {
  color: var(--color-text-tertiary);
}
.bcn-sr__split {
  display: flex;
  align-items: flex-start;
  gap: var(--spacing-500);
}
.bcn-sr__rail {
  flex: none;
  width: 220px;
  position: sticky;
  top: var(--spacing-400);
  display: flex;
  flex-direction: column;
  gap: 1px;
}
.bcn-sr__scope {
  display: flex;
  align-items: center;
  gap: var(--spacing-200);
  width: 100%;
  padding: var(--spacing-200) var(--spacing-250);
  border: 0;
  border-radius: var(--radius-200);
  background: transparent;
  color: var(--color-text-secondary);
  font-family: inherit;
  font-size: var(--type-size-150);
  text-align: left;
  cursor: pointer;
  transition:
    background 0.12s ease,
    color 0.12s ease;
}
.bcn-sr__scope--active {
  background: var(--color-primary);
  color: var(--color-text-inverse);
  font-weight: var(--font-weight-semibold);
}
.bcn-sr__scope-label {
  flex: 1;
  min-width: 0;
  overflow: hidden;
  text-overflow: ellipsis;
  white-space: nowrap;
}
.bcn-sr__scope-count {
  flex: none;
  font-size: 11px;
  font-variant-numeric: tabular-nums;
  opacity: 0.8;
}
.bcn-sr__main {
  flex: 1 1 auto;
  min-width: 0;
  display: flex;
  flex-direction: column;
  gap: var(--spacing-400);
  border-left: 1px solid var(--color-border);
  padding-left: var(--spacing-500);
}
.bcn-sr__count {
  margin: 0;
  font-size: var(--type-size-150);
  color: var(--color-text-secondary);
}
.bcn-sr__landing {
  padding: var(--spacing-700) 0;
}
.bcn-sr__landing[hidden],
.bcn-sr__results[hidden] {
  display: none;
}
.bcn-sr__results {
  display: flex;
  flex-direction: column;
  gap: var(--spacing-500);
}
.bcn-sr__group {
  display: flex;
  flex-direction: column;
  gap: var(--spacing-150);
}
.bcn-sr__group-head {
  display: flex;
  align-items: center;
  gap: var(--spacing-200);
  padding: 0 var(--spacing-200) var(--spacing-150);
  border-bottom: 1px solid var(--color-border-light);
}
.bcn-sr__group-label {
  font-size: var(--type-size-200);
  font-weight: var(--font-weight-semibold);
  color: var(--color-text-primary);
}
.bcn-sr__group-count {
  font-size: var(--type-size-100);
  font-variant-numeric: tabular-nums;
  color: var(--color-text-secondary);
  background: transparent;
  border: 1px solid var(--color-border);
  border-radius: var(--radius-100);
  padding: 0 6px;
  line-height: 1.5;
}
.bcn-sr__rows {
  display: flex;
  flex-direction: column;
  gap: 2px;
}
.bcn-sr__row {
  display: flex;
  flex-direction: column;
  gap: var(--spacing-150);
  padding: var(--spacing-200) var(--spacing-300);
  border-radius: var(--radius-200);
  background: transparent;
  color: var(--color-text-primary);
  text-decoration: none;
  transition: background 0.12s ease;
}
.bcn-sr__row-head {
  display: flex;
  align-items: center;
  min-width: 0;
}
.bcn-sr__row-titlerow {
  flex: 1;
  display: flex;
  align-items: center;
  gap: var(--spacing-200);
  min-width: 0;
}
.bcn-sr__row-title {
  flex: 0 1 auto;
  min-width: 0;
  font-size: var(--type-size-200);
  font-weight: var(--font-weight-semibold);
  color: var(--color-text-primary);
  white-space: nowrap;
  overflow: hidden;
  text-overflow: ellipsis;
}
.bcn-sr__row-snippet {
  margin-top: var(--spacing-100);
  padding: var(--spacing-250) var(--spacing-300);
  border: 1px solid var(--color-border);
  border-radius: var(--radius-100);
  background: var(--color-surface);
  font-family: var(--font-decorative);
  font-size: var(--type-size-150);
  line-height: 1.6;
  color: var(--color-text-primary);
}
.bcn-sr__row-snippet[hidden] {
  display: none;
}
.bcn-sr__row-code {
  flex: none;
  padding: 1px 6px;
  border-radius: var(--radius-100);
  font-size: var(--type-size-100);
  font-weight: var(--font-weight-semibold);
  line-height: 1.4;
  white-space: nowrap;
  color: var(--color-commitment);
  background: color-mix(in srgb, var(--color-commitment) 12%, white);
}
.bcn-sr__empty[hidden] {
  display: none;
}
.bcn-sr--idle .bcn-sr__scope {
  color: var(--color-text-tertiary);
  cursor: default;
}
.bcn-sr--idle .bcn-sr__scope-count {
  display: none;
}
.bcn-sr__search:focus-within {
  border-color: var(--color-primary);
  box-shadow: 0 0 0 3px var(--color-primary-subtle);
}
.bcn-sr__group[hidden] {
  display: none;
}
.bcn-sr__row-title mark,
.bcn-sr__row-snippet mark {
  background: #fde047;
  color: var(--color-text-primary);
  border-radius: 2px;
  padding: 0 1px;
}
.bcn-sr__row[hidden] {
  display: none;
}
.esa-empty-state {
  --_empty-icon-size: var(--empty-state-icon-size-md, 48px);
  --_empty-title-size: 16px;
  --_empty-desc-size: 14px;
  --_empty-gap: var(--empty-state-gap, var(--spacing-200, 0.5rem));
  display: flex;
  flex-direction: column;
  align-items: center;
  justify-content: center;
  text-align: center;
  padding: var(--spacing-600, 2rem) var(--spacing-400, 1rem);
  gap: var(--_empty-gap);
}
.esa-empty-state__icon {
  color: var(--empty-state-icon-color, var(--color-text-muted, #737373));
  margin-bottom: var(--spacing-100, 0.25rem);
  display: inline-flex;
}
.esa-empty-state__icon svg {
  width: var(--_empty-icon-size);
  height: var(--_empty-icon-size);
}
.esa-empty-state__title {
  margin: 0;
  font-size: var(--_empty-title-size);
  font-weight: 600;
  color: var(--empty-state-title-color, var(--color-text-primary, #171717));
}
.esa-empty-state__description {
  margin: 0;
  font-size: var(--_empty-desc-size);
  color: var(--empty-state-description-color, var(--color-text-secondary, #525252));
  max-width: 360px;
}
.esa-empty-state__actions {
  margin-top: var(--spacing-200, 0.5rem);
}

.bcn-sr__rows {
  display: flex;
  flex-direction: column;
  gap: 2px;
}
.bcn-sr__row {
  display: flex;
  flex-direction: column;
  gap: var(--spacing-150);
  padding: var(--spacing-200) var(--spacing-300);
  border-radius: var(--radius-200);
  background: transparent;
  color: var(--color-text-primary);
  text-decoration: none;
  transition: background 0.12s ease;
}
.bcn-sr__row-head {
  display: flex;
  align-items: center;
  min-width: 0;
}
.bcn-sr__row-titlerow {
  flex: 1;
  display: flex;
  align-items: center;
  gap: var(--spacing-200);
  min-width: 0;
}
.bcn-sr__row-code {
  flex: none;
  padding: 1px 6px;
  border-radius: var(--radius-100);
  font-size: var(--type-size-100);
  font-weight: var(--font-weight-semibold);
  line-height: 1.4;
  white-space: nowrap;
  color: var(--color-commitment);
  background: color-mix(in srgb, var(--color-commitment) 12%, white);
}
.bcn-sr__row-title {
  flex: 0 1 auto;
  min-width: 0;
  font-size: var(--type-size-200);
  font-weight: var(--font-weight-semibold);
  color: var(--color-text-primary);
  white-space: nowrap;
  overflow: hidden;
  text-overflow: ellipsis;
}
.bcn-sr__row-snippet {
  margin-top: var(--spacing-100);
  padding: var(--spacing-250) var(--spacing-300);
  border: 1px solid var(--color-border);
  border-radius: var(--radius-100);
  background: var(--color-surface);
  font-family: var(--font-decorative);
  font-size: var(--type-size-150);
  line-height: 1.6;
  color: var(--color-text-primary);
}
.bcn-sr__row-title mark,
.bcn-sr__row-snippet mark {
  background: #fde047;
  color: var(--color-text-primary);
  border-radius: 2px;
  padding: 0 1px;
}
.bcn-sr__row[hidden] {
  display: none;
}
.bcn-sr__row-snippet[hidden] {
  display: none;
}
